<?php
    session_start();

    $timeout = 120;

    if (!isset($_SESSION['usuario'])) {
        header("Location: ../login.php");
        exit;
    }

    if (isset($_SESSION['last_activity']) && (time() - $_SESSION['last_activity'] > $timeout)) {
        session_unset();
        session_destroy();
        header("Location: ../login.php");
        exit;
    }

    $_SESSION['last_activity'] = time();
?>